package com.hospital.management.controller.admin;import com.hospital.management.service.*;import com.hospital.management.service.impl.PatientServiceImpl;import com.hospital.management.util.RequestUtil;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/admin/patients/status")public class PatientStatusServlet extends HttpServlet{private final PatientService service;public PatientStatusServlet(){this(new PatientServiceImpl());}public PatientStatusServlet(PatientService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws IOException{r.sendError(405,"Patient status changes require POST");}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws IOException{Long id=Form.id(q.getParameter("patientId"));String a=q.getParameter("action");if(id==null||!("activate".equals(a)||"deactivate".equals(a))){r.sendError(400);return;}ServiceResult<Void>x="activate".equals(a)?service.activatePatient(id,RequestUtil.buildAuditContext(q)):service.deactivatePatient(id,RequestUtil.buildAuditContext(q));String m=x.isSuccess()?"message="+a+"d":"error="+(x.getStatus()==ServiceResult.Status.CONFLICT?"blocked":"error");r.sendRedirect(q.getContextPath()+"/admin/patients?"+m);}}
